namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "Flour, Eggs, Milk, Butter, Sugar, Baking Powder", Steps = "1. Mix dry ingredients\n2. Whisk wet ingredients\n3. Combine and stir until just mixed\n4. Cook on griddle until bubbles form\n5. Flip and cook until golden" },
        new() { Id = 2, Title = "Eggs Benedict", Category = "Breakfast", Ingredients = "English Muffins, Eggs, Ham, Butter, Lemon Juice, Egg Yolks", Steps = "1. Toast muffins\n2. Poach eggs\n3. Make hollandaise sauce\n4. Assemble: muffin, ham, egg, sauce" },
        new() { Id = 3, Title = "Caesar Salad", Category = "Lunch", Ingredients = "Romaine Lettuce, Parmesan, Croutons, Caesar Dressing, Lemon", Steps = "1. Wash and chop romaine\n2. Make dressing with anchovy, garlic, lemon\n3. Toss lettuce with dressing\n4. Top with croutons and parmesan" },
        new() { Id = 4, Title = "Grilled Chicken Wrap", Category = "Lunch", Ingredients = "Chicken Breast, Tortilla, Lettuce, Tomato, Ranch Dressing", Steps = "1. Season and grill chicken\n2. Slice chicken\n3. Warm tortilla\n4. Layer ingredients and wrap" },
        new() { Id = 5, Title = "Spaghetti Bolognese", Category = "Dinner", Ingredients = "Spaghetti, Ground Beef, Tomato Sauce, Onion, Garlic, Italian Herbs", Steps = "1. Brown ground beef with onion and garlic\n2. Add tomato sauce and herbs\n3. Simmer for 30 minutes\n4. Cook pasta\n5. Serve sauce over pasta" },
        new() { Id = 6, Title = "Grilled Salmon", Category = "Dinner", Ingredients = "Salmon Fillet, Lemon, Dill, Olive Oil, Salt, Pepper", Steps = "1. Season salmon with oil, lemon, dill\n2. Preheat grill to medium-high\n3. Grill skin-side down 4 minutes\n4. Flip and cook 3 more minutes" },
        new() { Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "Butter, Sugar, Brown Sugar, Eggs, Vanilla, Flour, Chocolate Chips", Steps = "1. Cream butter and sugars\n2. Beat in eggs and vanilla\n3. Mix in flour\n4. Fold in chocolate chips\n5. Bake at 375°F for 10 minutes" },
        new() { Id = 8, Title = "Tiramisu", Category = "Desserts", Ingredients = "Ladyfingers, Mascarpone, Espresso, Cocoa Powder, Eggs, Sugar", Steps = "1. Brew and cool espresso\n2. Whisk egg yolks with sugar\n3. Fold in mascarpone\n4. Dip ladyfingers in espresso\n5. Layer cookies and cream\n6. Dust with cocoa" },
    ];

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes with our community.</p>

<h2 class="mt-4">Browse by Category</h2>

<div class="row mt-3">
    @foreach (var category in Categories)
    {
        <div class="col-md-3 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h5 class="card-title">@category</h5>
                    <a href="category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

