@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes with our community.</p>

<h2 class="mt-4">Browse by Category</h2>

<div class="row mt-3">
    @foreach (var category in Categories)
    {
        <div class="col-md-3 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h5 class="card-title">@category</h5>
                    <a href="category/@category" class="btn btn-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

arguments.file_text:
@page "/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @if (recipe.AverageRating > 0)
                            {
                                <span>@recipe.AverageRating.ToString("0.0") ★ (@recipe.Ratings.Count ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Services.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary">@Recipe.Category</span>

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3 class="mt-4">Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
            {
                text = text[3..];
            }
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
            {
                text = text[4..];
            }
            <li>@text</li>
        }
    </ol>

    <h3 class="mt-4">Rate this Recipe</h3>
    <StarRating RecipeId="Recipe.Id" CurrentAverage="Recipe.AverageRating" RatingCount="Recipe.Ratings.Count" />

    <a href="category/@Recipe.Category" class="btn btn-link mt-3">← Back to @Recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Services.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                title="Rate @star stars"
                disabled="@HasRated">
            @(star <= _selectedRating ? "★" : "☆")
        </button>
    }
    @if (HasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
    <div class="text-muted small mt-1">
        @if (RatingCount > 0 || HasRated)
        {
            <span>Average: @_displayAverage.ToString("0.0") ★ (@_displayCount ratings)</span>
        }
        else
        {
            <span>Be the first to rate!</span>
        }
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating;
    private bool HasRated;
    private double _displayAverage;
    private int _displayCount;

    protected override void OnInitialized()
    {
        _displayAverage = CurrentAverage;
        _displayCount = RatingCount;
    }

    private void SubmitRating(int stars)
    {
        if (HasRated) return;
        RecipeService.AddRating(RecipeId, stars);
        _selectedRating = stars;
        HasRated = true;
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            _displayAverage = recipe.AverageRating;
            _displayCount = recipe.Ratings.Count;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/" class="alert-link">Back to home</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Lunch">Lunch</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="4"
                           placeholder="List ingredients separated by commas" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="6"
                           placeholder="Describe each step on a new line" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private bool _submitted;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(_model.Title, _model.Category, _model.Ingredients, _model.Steps);
        _submitted = true;
    }

    private sealed class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

